<?php
// ── Session & Redirect ───────────────────────────────────────────
session_start();

// Already logged in? Send them to the right page
if (isset($_SESSION['user_id'])) {
    header('Location: ' . ($_SESSION['role'] === 'admin' ? 'admin.php' : 'user.php'));
    exit;
}

require_once 'db.php';

$error = '';

// ── Handle Login POST ────────────────────────────────────────────
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $student_id = trim($_POST['student_id'] ?? '');
    $password   = $_POST['password'] ?? '';

    if (!$student_id || !$password) {
        $error = 'Please enter your Student ID and password.';
    } else {

        // ── 1) Check admins table first ──────────────────────────
        $stmt = $pdo->prepare('SELECT * FROM admins WHERE username = ? LIMIT 1');
        $stmt->execute([$student_id]);
        $admin = $stmt->fetch();

        if ($admin && password_verify($password, $admin['password'])) {
            session_regenerate_id(true);

            $nameParts = explode(' ', $admin['full_name'], 2);
            $_SESSION['user_id']        = $admin['id'];
            $_SESSION['student_id']     = $admin['username'];
            $_SESSION['first_name']     = $nameParts[0] ?? '';
            $_SESSION['last_name']      = $nameParts[1] ?? '';
            $_SESSION['email']          = $admin['email'];
            $_SESSION['phone']          = '';
            $_SESSION['dob']            = '';
            $_SESSION['role']           = 'admin';
            $_SESSION['admin_id']       = $admin['id'];
            $_SESSION['admin_name']     = $admin['full_name'];
            $_SESSION['admin_username'] = $admin['username'];
            $_SESSION['admin_email']    = $admin['email'];
            $_SESSION['has_voted']      = 0;

            header('Location: admin.php?section=overview');
            exit;
        }

        // ── 2) Check students table ──────────────────────────────
        $stmt = $pdo->prepare('SELECT * FROM students WHERE student_id = ? LIMIT 1');
        $stmt->execute([$student_id]);
        $student = $stmt->fetch();

        if (!$student) {
            $error = 'Invalid Student ID or password. Please try again.';
        } elseif ($student['approval_status'] === 'Pending') {
            $error = 'pending';
        } elseif ($student['approval_status'] === 'Rejected') {
            $error = 'rejected';
        } elseif (!password_verify($password, $student['password_hash'])) {
            $error = 'Invalid Student ID or password. Please try again.';
        } else {
            // ── All good — start student session ─────────────────
            session_regenerate_id(true);

            $_SESSION['user_id']         = (int)$student['id'];
            $_SESSION['student_id']      = $student['student_id'];
            $_SESSION['first_name']      = $student['first_name'];
            $_SESSION['last_name']       = $student['last_name'];
            $_SESSION['email']           = $student['email'];
            $_SESSION['phone']           = $student['phone']     ?? '';
            $_SESSION['dob']             = $student['birthdate'] ?? '';
            $_SESSION['role']            = 'student';
            $_SESSION['has_voted']       = (int)$student['has_voted'];
            $_SESSION['approval_status'] = 'Approved';

            header('Location: user.php');
            exit;
        }
    }
}
