    <!-- ── Forgot Password Modal ─────────────────────────── -->
    <div class="fp-overlay" id="fpOverlay">
        <div class="fp-modal">
            <div class="fp-modal-title">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                    <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                </svg>
                Reset Password
            </div>
            <p>Enter the email address linked to your account and we'll send you a reset link.</p>

            <div class="fp-alert" id="fpAlert"></div>

            <form id="fpForm" onsubmit="sendReset(event)">
                <div class="field">
                    <label for="fp_email">Email Address</label>
                    <div class="fp-field-wrap">
                        <input type="email" id="fp_email" name="fp_email"
                            placeholder="yourname@email.com" required />
                        <span class="fp-field-icon">
                            <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                                <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z" />
                                <polyline points="22,6 12,13 2,6" />
                            </svg>
                        </span>
                    </div>
                </div>
                <button class="btn-send" type="submit" id="fpSendBtn">Send Reset Link →</button>
                <button class="btn-cancel" type="button" onclick="closeFP()">Cancel</button>
            </form>
        </div>
    </div>

    <script>
        function togglePassword() {
            const input = document.getElementById('password');
            const icon = document.getElementById('eyeIcon');
            if (input.type === 'password') {
                input.type = 'text';
                icon.innerHTML = `
                <path d="M17.94 17.94A10.07 10.07 0 0112 20c-7 0-11-8-11-8a18.45 18.45 0 015.06-5.94"/>
                <path d="M9.9 4.24A9.12 9.12 0 0112 4c7 0 11 8 11 8a18.5 18.5 0 01-2.16 3.19"/>
                <line x1="1" y1="1" x2="23" y2="23"/>`;
            } else {
                input.type = 'password';
                icon.innerHTML = `
                <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
                <circle cx="12" cy="12" r="3"/>`;
            }
        }

        function openFP(e) {
            e.preventDefault();
            document.getElementById('fpOverlay').classList.add('open');
        }

        function closeFP() {
            document.getElementById('fpOverlay').classList.remove('open');
            const alert = document.getElementById('fpAlert');
            alert.className = 'fp-alert';
            alert.textContent = '';
            document.getElementById('fp_email').value = '';
            document.getElementById('fpSendBtn').disabled = false;
            document.getElementById('fpSendBtn').textContent = 'Send Reset Link →';
        }

        document.getElementById('fpOverlay').addEventListener('click', function(e) {
            if (e.target === this) closeFP();
        });

        async function sendReset(e) {
            e.preventDefault();
            const email = document.getElementById('fp_email').value.trim();
            const btn = document.getElementById('fpSendBtn');
            const alertEl = document.getElementById('fpAlert');
            btn.disabled = true;
            btn.textContent = 'Sending…';
            alertEl.className = 'fp-alert';
            alertEl.textContent = '';
            try {
                const res = await fetch('forgot_password.php', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/x-www-form-urlencoded'
                    },
                    body: 'email=' + encodeURIComponent(email)
                });
                const data = await res.json();
                alertEl.className = 'fp-alert ' + (data.ok ? 'ok' : 'err');
                alertEl.textContent = data.message;
                if (data.ok) {
                    btn.textContent = 'Email Sent ✓';
                } else {
                    btn.disabled = false;
                    btn.textContent = 'Send Reset Link →';
                }
            } catch {
                alertEl.className = 'fp-alert err';
                alertEl.textContent = 'Network error. Please try again.';
                btn.disabled = false;
                btn.textContent = 'Send Reset Link →';
            }
        }
    </script>
</body>

</html>